sys_transform_script.script:
(function runTransformScript(source, map, log, target /*undefined onStart*/ ) {
    // Populate a cmn_location Reference based on location code
	// for rows not already marked ignore and which do not yet
	// have a Location

    // 	{
    //   "752": {
    //     "valid": true,
    //     "message": "",
    //     "reference": {
    //       "label": "10065 East Harvard Avenue, Denver,CO",
    //       "value": "25ab8f300a0a0bb300d99f69c3ac24cd"
    //     }
    //   },...}
    var parser = new x_42999_decision_0.DecisionParser("Vendor Location Lookup");
    var entries = parser.getMap(parser.DEFAULT_HELPER.bind(parser), parser.Filter.VALID);

    if (Object.keys(entries).length > 0) {

        // Get import rows having one of these locations, where the
        // Location reference is not already set
        var gr_is_row = new GlideRecord("x_42999_decision_0_hardware_location");
        gr_is_row.addQuery("sys_import_set", import_set.sys_id);
		gr_is_row.addQuery("u_ignore", false);
        gr_is_row.addEncodedQuery("u_locationIN" + Object.keys(entries).join(","));
        gr_is_row.addEncodedQuery("u_location_refISEMPTY");
        gr_is_row.query();
        while (gr_is_row.hasNext()) {
            gr_is_row.next();
            var locationCode = gr_is_row.getValue("u_location");
            var entry = entries[locationCode];
            gr_is_row.setValue("u_location_ref", entry.reference.value);
            gr_is_row.update();
        }
    }
})(source, map, log, target);
